MERGE INTO VEHICLES tgt
USING (
select VEHICLEID,t.DISTANCE,t.ODOMETER,t.odometer + t.distance ending_odo,lead(t.tripdate) OVER (PARTITION BY r.VEHICLEID ORDER BY t.TRIPDATE) nxt
from trips t
inner join rigs r on (r.tripid = t.tripid and t.distance > 0)
where t.state = 3 AND r.vehicleid = 651
) src
ON (src.vehicleid = tgt.VEHICLEID AND src.nxt Is null)
WHEN MATCHED THEN UPDATE SET tgt.ODOMETER = src.ending_odo;



    
